import React from 'react';

const Footer = () => {
    const currentYear = new Date().getFullYear();

    return (
        <footer id="footer" className="footer position-relative py-5 mt-5">
            <div className="container">
                <div className="glass-v2 p-5 mb-0" style={{ borderRadius: '40px 40px 0 0', borderBottom: 'none' }}>
                    <h3 className="text-gradient fw-900 mb-3" style={{ fontSize: '2.5rem' }}>Deepak Aruldoss</h3>
                    <p className="text-white opacity-75 mb-4">Engineering high-performance backend ecosystems.</p>
                    <div className="social-links d-flex justify-content-center mb-5 gap-4">
                        <a href="https://www.facebook.com/share/18az6SS6kn/" target="_blank" rel="noreferrer" title="Facebook"><i className="bi bi-facebook fs-3"></i></a>
                        <a href="https://www.instagram.com/deepakarul55?igsh=YXFwMXhwczFhY2pl" target="_blank" rel="noreferrer" title="Instagram"><i className="bi bi-instagram fs-3"></i></a>
                        <a href="https://www.linkedin.com/in/deepak-aruldoss-40426b218" target="_blank" rel="noreferrer" title="LinkedIn"><i className="bi bi-linkedin fs-3"></i></a>
                    </div>
                    <div className="copyright text-muted small border-top border-secondary pt-4">
                        <span>&copy; {currentYear}</span> <strong className="px-1 text-white">Deepak Aruldoss</strong> <span>Professional Software Architecture</span>
                    </div>
                </div>
            </div>
        </footer>
    );
};

export default Footer;
